package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class JsonWriterTest {

  private JsonWriter jsonWriter;
  private StringWriter stringWriter;

  @BeforeEach
  void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  void jsonValue_nullValue_callsNullValueAndReturnsThis() throws Exception {
    JsonWriter spyWriter = spy(jsonWriter);
    doReturn(spyWriter).when(spyWriter).nullValue();

    JsonWriter result = spyWriter.jsonValue(null);

    verify(spyWriter).nullValue();
    assertSame(spyWriter, result);
  }

  @Test
  void jsonValue_nonNullValue_writesValue() throws Exception {
    // Arrange
    String value = "{\"key\":\"value\"}";

    // Use reflection to set deferredName field to null (default) to avoid writeDeferredName side effect
    Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);

    Method beforeValueMethod = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValueMethod.setAccessible(true);

    // Spy on jsonWriter to verify writeDeferredName and beforeValue called
    JsonWriter spyWriter = spy(jsonWriter);

    doCallRealMethod().when(spyWriter).jsonValue(anyString());

    // Act
    JsonWriter result = spyWriter.jsonValue(value);

    // Assert
    verify(spyWriter).writeDeferredName();
    verify(spyWriter).beforeValue();
    assertEquals(value, stringWriter.toString());
    assertSame(spyWriter, result);
  }

  @Test
  void jsonValue_callsWriteDeferredNameAndBeforeValue() throws Exception {
    String value = "123";

    JsonWriter spyWriter = spy(jsonWriter);
    doNothing().when(spyWriter).writeDeferredName();
    doNothing().when(spyWriter).beforeValue();

    JsonWriter result = spyWriter.jsonValue(value);

    verify(spyWriter).writeDeferredName();
    verify(spyWriter).beforeValue();
    assertSame(spyWriter, result);
  }
}

